double Dot3(const double lhs[3], const double rhs[3])
{
    return lhs[0] * rhs[0] + lhs[1] * rhs[1] + lhs[2] * rhs[2];
}

void Cross3(const double lhs[3], const double rhs[3], double result[3])
{
    result[0] = lhs[1] * rhs[2] - lhs[2] * rhs[1];
    result[1] = lhs[2] * rhs[0] - lhs[0] * rhs[2];
    result[2] = lhs[0] * rhs[1] - lhs[1] * rhs[0];
}

double Length3(const double value[3])
{
    return std::sqrt(Dot3(value, value));
}

bool Normalize3(double value[3])
{
    const double length = Length3(value);
    if (length <= 1.0e-9)
    {
        return false;
    }

    value[0] /= length;
    value[1] /= length;
    value[2] /= length;
    return true;
}

bool CreateLineFromPoints(const double startPoint[3], const double endPoint[3], tag_t& lineTag)
{
    UF_CURVE_line_t lineData = {};
    for (int axis = 0; axis < 3; ++axis)
    {
        lineData.start_point[axis] = startPoint[axis];
        lineData.end_point[axis] = endPoint[axis];
    }

    lineTag = NULL_TAG;
    return UF_CURVE_create_line(&lineData, &lineTag) == 0 && lineTag != NULL_TAG;
}

bool GetLineMidpoint(tag_t lineTag, double midpoint[3])
{
    UF_CURVE_line_t lineData = {};
    if (UF_CURVE_ask_line_data(lineTag, &lineData) != 0)
    {
        return false;
    }
    midpoint[0] = (lineData.start_point[0] + lineData.end_point[0]) * 0.5;
    midpoint[1] = (lineData.start_point[1] + lineData.end_point[1]) * 0.5;
    midpoint[2] = (lineData.start_point[2] + lineData.end_point[2]) * 0.5;
    return true;
}

void Midpoint3(const double point1[3], const double point2[3], double midpoint[3])
{
    midpoint[0] = (point1[0] + point2[0]) * 0.5;
    midpoint[1] = (point1[1] + point2[1]) * 0.5;
    midpoint[2] = (point1[2] + point2[2]) * 0.5;
}

double ComputeDirectedAngleDegrees(
    const double fromNormal[3],
    const double toNormal[3],
    const double axisDirection[3])
{
    double lhs[3] = {fromNormal[0], fromNormal[1], fromNormal[2]};
    double rhs[3] = {toNormal[0], toNormal[1], toNormal[2]};
    double axis[3] = {axisDirection[0], axisDirection[1], axisDirection[2]};

    if (!Normalize3(lhs) || !Normalize3(rhs) || !Normalize3(axis))
    {
        return 0.0;
    }

    double cross[3] = {0.0, 0.0, 0.0};
    Cross3(lhs, rhs, cross);
    const double sinValue = Dot3(axis, cross);
    const double cosValue = std::max(-1.0, std::min(1.0, Dot3(lhs, rhs)));
    double angle = std::atan2(sinValue, cosValue) * 180.0 / 3.14159265358979323846;
    if (angle < 0.0)
    {
        angle += 360.0;
    }

    return angle;
}

